css:
color-scheme: dark;
  --app-bg: #0b0907;
  --app-surface: rgba(255, 220, 180, 0.03);
  --app-surface-hover: rgba(255, 220, 180, 0.05);
  --app-border: rgba(255, 220, 180, 0.07);
  --app-border-strong: rgba(255, 200, 140, 0.14);
  --app-text: #f5f0ea;
  --app-text-muted: #9a9188;
  --app-accent: #e4a855;
  --app-accent-soft: rgba(228, 168, 85, 0.15);
  --app-accent-border: rgba(228, 168, 85, 0.32);
  --app-accent-nav: rgba(228, 168, 85, 0.1);
  --app-elevated: #12100c;
  --app-glow-1: rgba(255, 190, 90, 0.14);
  --app-glow-2: rgba(180, 80, 50, 0.08);
  --app-card-shadow: 0 20px 40px rgba(0, 0, 0, 0.5), inset 0 1px 0 rgba(255, 220, 180, 0.08), inset 0 -1px 0 rgba(0, 0, 0, 0.4);
  --app-sidebar-bg: radial-gradient(circle at 16% -2%, var(--app-glow-1), transparent 44%), radial-gradient(circle at 88% 108%, var(--app-glow-2), transparent 42%), var(--app-bg);
  --app-shell-bg: var(--app-sidebar-bg);
  --media-snake-1: rgba(180, 120, 50, 0.14);
  --media-snake-2: rgba(230, 175, 90, 0.6);
  --media-snake-3: rgba(255, 230, 190, 0.95);
  --media-snake-4: rgba(220, 130, 70, 0.75);
  --bg-primary: var(--app-bg);
  --bg-secondary: var(--app-elevated);
  --bg-elevated: #181410;
  --bg-glass: rgba(14, 12, 9, 0.88);
  --text-primary: var(--app-text);
  --text-secondary: var(--app-text-muted);
  --text-tertiary: rgba(154, 145, 136, 0.72);
  --accent: var(--app-accent);
  --accent-blue: var(--app-accent);
  --focus-glow: rgba(228, 168, 85, 0.24);
